_sage_const_1 = Integer(1); _sage_const_3 = Integer(3); _sage_const_0 = Integer(0); _sage_const_2 = Integer(2); _sage_const_4 = Integer(4); _sage_const_7 = Integer(7); _sage_const_13 = Integer(13); _sage_const_60 = Integer(60); _sage_const_6 = Integer(6); _sage_const_1en6 = RealNumber('1e-6')# Tenfold base C' : u^3 + x*u + (y + x^2 + a) = 0 over E0 : y^2 + 2xy + y = x^3.
# Genus-6 CERTIFICATE: count #C'(F_{p^k}) for k = 1..6, Newton -> elementary symmetric
